 1→import { useEffect, useState } from "react";
 2→import { loadBlpDataUrl, useNineSliceButton } from "../utils/glueButton";
 3→import type { NineSliceUrls } from "../utils/glueButton";
 4→
 5→const PATHS = {
 6→  bg: "/buttons/glue/GlueScreen-Button1-BackdropBackground.blp",
 7→  bgDown: "/buttons/glue/GlueScreen-Button1-BackdropBackground-Down.blp",
 8→  bgDisabled:
 9→    "/buttons/glue/GlueScreen-Button1-BackdropBackground-Disabled.blp",
10→  border: "/buttons/glue/GlueScreen-Button1-BackdropBorder.blp",
11→  borderDown: "/buttons/glue/GlueScreen-Button1-BackdropBorder-Down.blp",
12→  borderDisabled:
13→    "/buttons/glue/GlueScreen-Button1-BackdropBorder-Disabled.blp",
14→  hover: "/buttons/glue/bnet-button01-highlight-mouse.blp",
15→};
16→
17→const pressedOffsetX = -2;
18→const pressedOffsetY = 3;
19→
20→interface Props {
21→  onClick?: () => void;
22→  disabled?: boolean;
23→  children: React.ReactNode;
24→}
25→
26→export default function GlueSmallButton({ onClick, disabled, children }: Props) {
27→  const [urls, setUrls] = useState<NineSliceUrls>({
28→    bg: "",
29→    bgDown: "",
30→    bgDisabled: "",
31→    border: "",
32→    borderDown: "",
33→    borderDisabled: "",
34→    hover: "",
35→  });
36→
37→  useEffect(() => {
38→    void Promise.all(Object.values(PATHS).map((p) => loadBlpDataUrl(p))).then(
39→      ([bg, bgDown, bgDisabled, border, borderDown, borderDisabled, hover]) => {
40→        setUrls({ bg, bgDown, bgDisabled, border, borderDown, borderDisabled, hover });
41→      },
42→    );
43→  }, []);
44→
45→  const { canvasRef, pressed, handlers } = useNineSliceButton(urls, disabled);
46→
47→  return (
48→    <button
49→      type="button"
50→      className="glue-small-button"
51→      disabled={disabled}
52→      onClick={onClick}
53→      {...handlers}
54→    >
55→      <canvas ref={canvasRef} className="glue-screen-canvas" />
56→      <span
57→        style={{
58→          transform: pressed
59→            ? `translate(${pressedOffsetX}px, ${pressedOffsetY}px)`
60→            : "none",
61→        }}
62→      >
63→        {children}
64→      </span>
65→    </button>
66→  );
67→}
