33→export default function GlueMenuButton({
34→  onClick,
35→  disabled,
36→  variant = "default",
37→  children,
38→}: Props) {
39→  const [urls, setUrls] = useState<NineSliceUrls>({
40→    bg: "",
41→    bgDown: "",
42→    bgDisabled: "",
43→    border: "",
44→    borderDown: "",
45→    borderDisabled: "",
46→    hover: "",
47→  });
48→  const [frameUrl, setFrameUrl] = useState("");
49→
50→  useEffect(() => {
51→    void Promise.all([
52→      ...Object.values(BUTTON_PATHS).map((p) => loadBlpDataUrl(p)),
53→      loadBlpDataUrl(FRAME_PATHS[variant]),
54→    ]).then(
55→      ([
56→        bg,
57→        bgDown,
58→        bgDisabled,
59→        border,
60→        borderDown,
61→        borderDisabled,
62→        hover,
63→        frame,
64→      ]) => {
65→        setUrls({ bg, bgDown, bgDisabled, border, borderDown, borderDisabled, hover });
66→        setFrameUrl(frame);
67→      },
68→    );
69→  }, [variant]);
70→
71→  const { canvasRef, pressed, handlers } = useNineSliceButton(urls, disabled);
72→
73→  return (
74→    <div className="menu-button-shell">
75→      {frameUrl && <img src={frameUrl} alt="" className="menu-button-frame" />}
76→      <button
77→        type="button"
78→        className={`menu-button-inner${variant === "single" ? " menu-button-inner--single" : ""}`}
79→        disabled={disabled}
80→        onClick={onClick}
81→        {...handlers}
82→      >
83→        <canvas ref={canvasRef} className="menu-button-canvas" />
84→        <span
85→          className="menu-button-label"
86→          style={{
