88→              ? `translate(${pressedOffsetX}px, ${pressedOffsetY}px)`
89→              : "none",
90→            color: disabled ? "#808080" : undefined,
91→          }}
92→        >
93→          {children}
94→        </span>
95→      </button>
96→    </div>
97→  );
